// Map content_suggestions record to blog_posts schema
const item = $input.first();
const records = Array.isArray(item.json) ? item.json : [item.json];
const suggestion = records[0];

if (!suggestion || !suggestion.id) {
  const suggestionId = $('Webhook - Receive Request').first().json.body?.suggestion_id;
  throw new Error(`Suggestion not found for id: ${suggestionId}`);
}

// Validate platform — only blog suggestions should be published as blog posts
// But we allow any platform suggestion to generate a blog draft
const title_ar = suggestion.title_ar || '';
const title_en = suggestion.title_en || '';
const content_ar = suggestion.content_ar || '';
const content_en = suggestion.content_en || '';

// Generate slug from English title
const generateSlug = (title) => {
  if (!title) return 'untitled-' + Date.now();
  return title
    .toLowerCase()
    .trim()
    .replace(/[^a-z0-9\s-]/g, '')
    .replace(/\s+/g, '-')
    .replace(/-+/g, '-')
    .replace(/^-|-$/g, '')
    .substring(0, 80) + '-' + Date.now();
};

// Extract excerpt (first 200 chars)
const excerpt_ar = content_ar
  .replace(/#+\s*/g, '')
  .replace(/\*+/g, '')
  .replace(/\n+/g, ' ')
  .trim()
  .substring(0, 200);

const excerpt_en = content_en
  .replace(/#+\s*/g, '')
  .replace(/\*+/g, '')
  .replace(/\n+/g, ' ')
  .trim()
  .substring(0, 200);

// Determine category based on platform and topic from intel
const platform = suggestion.platform || 'blog';
const categoryMap = {
  blog: 'articles',
  tiktok: 'social-media',
  instagram: 'social-media',
  facebook: 'social-media',
  linkedin: 'thought-leadership'
};
const category = categoryMap[platform] || 'articles';

// Extract tags from hooks and title keywords
let tags = [];
try {
  const hooksData = suggestion.hooks;
  let hooksArr = [];
  if (typeof hooksData === 'string') {
    hooksArr = JSON.parse(hooksData);
  } else if (Array.isArray(hooksData)) {
    hooksArr = hooksData;
  }
  // Extract Arabic keywords (simple word extraction)
  const allText = title_ar + ' ' + hooksArr.join(' ');
  const words = allText.split(/[\s،,؟?!.]+/).filter(w => w.length > 3).slice(0, 8);
  tags = [...new Set(words)];
} catch (e) {
  tags = ['زيادة', 'محتوى'];
}

// Add platform tag
tags.push(platform);
tags.push('ziyada');

const slug = generateSlug(title_en || title_ar);

return [{
  json: {
    // Blog post fields
    title_ar: title_ar,
    title_en: title_en,
    content_ar: content_ar,
    content_en: content_en,
    excerpt_ar: excerpt_ar,
    excerpt_en: excerpt_en,
    slug: slug,
    category: category,
    tags: tags,
    author: 'Ziyada',
    published: false,
    status: 'draft',
    // Keep suggestion ref for update step
    _suggestion_id: suggestion.id,
    _suggestion_platform: platform
  }
}];

// Extract the new blog post ID from Supabase response
const item = $input.first();
const records = Array.isArray(item.json) ? item.json : [item.json];
const blogPost = records[0];

if (!blogPost || !blogPost.id) {
  throw new Error('Blog post insertion failed - no ID returned from Supabase');
}

// Pass blog_post_id and suggestion_id to next node
return [{
  json: {
    blog_post_id: blogPost.id,
    blog_post_slug: blogPost.slug,
    blog_post_status: blogPost.status,
    suggestion_id: $('Map to Blog Post Schema').first().json._suggestion_id
  }
}];

// Prepare final webhook response
const item = $input.first();
const updatedSuggestion = Array.isArray(item.json) ? item.json[0] : item.json;

// Get blog post data from earlier step
const blogData = $('Extract Blog Post ID').first().json;

return [{
  json: {
    blog_post_id: blogData.blog_post_id,
    blog_post_slug: blogData.blog_post_slug,
    suggestion_id: blogData.suggestion_id,
    suggestion_status: 'approved',
    status: 'draft_created',
    message: 'Blog draft created successfully. Review at your Supabase dashboard.',
    created_at: new Date().toISOString()
  }
}];
